"use client";

import { useEffect, useState } from "react";
import { X, Save, Loader2, Sparkles, Phone, Mail, Users, FileText, Target, User as UserIcon } from "lucide-react";
import { Activity } from "@/lib/services/activity-service";
import { Lead } from "@/lib/services/lead-service";
import { User } from "@/lib/services/user-service";

interface ActivityDialogProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    leads: Lead[];
    users: User[];
    initialData?: Activity;
    onSubmit: (data: Omit<Activity, "id" | "created_at" | "lead" | "user">) => void;
    isLoading?: boolean;
}

const activityTypes = [
    { label: "Call", value: "call", icon: Phone },
    { label: "Email", value: "email", icon: Mail },
    { label: "Meeting", value: "meeting", icon: Users },
    { label: "Note", value: "note", icon: FileText },
];

export function ActivityDialog({
    isOpen,
    onClose,
    title,
    leads,
    users,
    initialData,
    onSubmit,
    isLoading,
}: ActivityDialogProps) {
    const [formData, setFormData] = useState({
        type: initialData?.type || "note",
        note: initialData?.note || "",
        leadId: initialData?.leadId || "",
        userId: initialData?.userId || "",
    });



    if (!isOpen) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="w-full max-w-xl rounded-[40px] bg-white p-10 shadow-2xl shadow-blue-900/10 border border-zinc-100 animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                <div className="flex items-center justify-between mb-8">
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <Sparkles size={24} className="text-blue-500 animate-pulse" />
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">
                                {title}
                            </h2>
                        </div>
                        <p className="text-[10px] font-black tracking-[0.3em] text-zinc-400">Activity Logger</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-2xl p-4 text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all border border-transparent hover:border-zinc-100"
                    >
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Activity Type</label>
                            <div className="grid grid-cols-4 gap-3">
                                {activityTypes.map((type) => {
                                    const Icon = type.icon;
                                    const isSelected = formData.type === type.value;
                                    return (
                                        <button
                                            key={type.value}
                                            type="button"
                                            onClick={() => setFormData({ ...formData, type: type.value })}
                                            className={`flex flex-col items-center justify-center gap-2 p-5 rounded-[24px] border transition-all ${
                                                isSelected
                                                    ? "bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-600/30 scale-105"
                                                    : "bg-white border-zinc-100 text-zinc-400 hover:bg-zinc-50"
                                            }`}
                                        >
                                            <Icon size={20} />
                                            <span className="text-[10px] font-black tracking-widest">{type.label}</span>
                                        </button>
                                    );
                                })}
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                <FileText size={14} /> Notes / Details
                            </label>
                             <textarea
                                rows={4}
                                placeholder="Describe the operational specifics..."
                                value={formData.note}
                                onChange={(e) => setFormData({ ...formData, note: e.target.value })}
                                className="w-full rounded-[24px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300 resize-none"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <Target size={14} /> Related Lead
                                </label>
                                 <select
                                    required
                                    value={formData.leadId}
                                    onChange={(e) => setFormData({ ...formData, leadId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300 appearance-none"
                                >
                                    <option value="">Select Lead...</option>
                                    {leads.map((lead) => (
                                        <option key={lead.id} value={lead.id}>
                                            {lead.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <UserIcon size={14} /> Logged By
                                </label>
                                 <select
                                    value={formData.userId}
                                    onChange={(e) => setFormData({ ...formData, userId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="">Unknown</option>
                                    {users.map((user) => (
                                        <option key={user.id} value={user.id}>
                                            {user.name}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 pt-10">
                        <button
                            type="button"
                            onClick={onClose}
                            className="h-16 flex-1 rounded-[24px] text-xs font-black tracking-widest text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all"
                        >
                            Discard
                        </button>
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="h-16 flex-[2] flex items-center justify-center gap-4 rounded-[24px] bg-blue-600 text-xs font-black tracking-widest text-white shadow-2xl shadow-blue-600/30 hover:-translate-y-1 transition-all disabled:opacity-50 hover:bg-blue-700 active:scale-95"
                        >
                            {isLoading ? (
                                <Loader2 className="animate-spin" size={20} />
                            ) : (
                                <>
                                    <Save size={18} />
                                    Save
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { X, Save, Loader2, Sparkles } from "lucide-react";
import { Deal } from "@/lib/services/deal-service";
import { Lead } from "@/lib/services/lead-service";
 
interface DealDialogProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    leads: Lead[];
    initialData?: Deal;
    onSubmit: (data: Omit<Deal, "id" | "created_at" | "updated_at" | "lead">) => void;
    isLoading?: boolean;
}

export function DealDialog({
    isOpen,
    onClose,
    title,
    leads,
    initialData,
    onSubmit,
    isLoading,
}: DealDialogProps) {
    const [formData, setFormData] = useState({
        title: initialData?.title || "",
        amount: initialData?.amount || 0,
        stage: initialData?.stage || "new",
        leadId: initialData?.leadId || "",
    });



    if (!isOpen) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit(formData);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="w-full max-w-xl rounded-[48px] bg-white p-12 shadow-2xl shadow-blue-900/10 border border-zinc-100 animate-in zoom-in-95 duration-500">
                <div className="flex items-center justify-between mb-10">
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <Sparkles size={24} className="text-blue-500 animate-pulse" />
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">
                                {title}
                            </h2>
                        </div>
                        <p className="text-[10px] text-zinc-500 font-bold tracking-widest opacity-60">Track and manage your sales pipeline</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-2xl p-4 text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all border border-transparent hover:border-zinc-100"
                    >
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-8">
                    <div className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1">Deal Title</label>
                            <input
                                required
                                type="text"
                                placeholder="e.g. Enterprise Global Expansion"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Value ($)</label>
                                <input
                                    required
                                    type="number"
                                    placeholder="50000"
                                    value={formData.amount}
                                    onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Stage</label>
                                <select
                                    value={formData.stage}
                                    onChange={(e) => setFormData({ ...formData, stage: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="new">Target Acquisition</option>
                                    <option value="negotiation">Active Negotiation</option>
                                    <option value="closed_won">Operational Success</option>
                                    <option value="closed_lost">Tactical Withdrawal</option>
                                </select>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Associated Lead</label>
                            <select
                                required
                                value={formData.leadId}
                                onChange={(e) => setFormData({ ...formData, leadId: e.target.value })}
                                className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                            >
                                <option value="">Select Target Lead...</option>
                                {leads.map((lead) => (
                                    <option key={lead.id} value={lead.id}>
                                        {lead.name.toUpperCase()} ΓÇö {lead.email}
                                    </option>
                                ))}
                            </select>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 pt-8">
                        <button
                            type="button"
                            onClick={onClose}
                            className="h-16 flex-1 rounded-[24px] text-xs font-black uppercase tracking-widest text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all"
                        >
                            Discard
                        </button>
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="h-16 flex-[2] flex items-center justify-center gap-4 rounded-[24px] bg-blue-600 text-xs font-black uppercase tracking-widest text-white shadow-2xl shadow-blue-600/40 hover:-translate-y-1 transition-all disabled:opacity-50 hover:bg-blue-700 active:scale-95"
                        >
                            {isLoading ? (
                                <Loader2 className="animate-spin" size={20} />
                            ) : (
                                <>
                                    <Save size={18} />
                                    Save
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { X, Save, Loader2, Sparkles, Calendar, User as UserIcon, Target, AlignLeft } from "lucide-react";
import { Task } from "@/lib/services/task-service";
import { Lead } from "@/lib/services/lead-service";
import { User } from "@/lib/services/user-service";
 
interface TaskDialogProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    leads: Lead[];
    users: User[];
    initialData?: Task;
    onSubmit: (data: Omit<Task, "id" | "created_at" | "updated_at" | "lead" | "user">) => void;
    isLoading?: boolean;
}

export function TaskDialog({
    isOpen,
    onClose,
    title,
    leads,
    users,
    initialData,
    onSubmit,
    isLoading,
}: TaskDialogProps) {
    const [formData, setFormData] = useState({
        title: initialData?.title || "",
        description: initialData?.description || "",
        status: initialData?.status || "pending",
        dueDate: initialData?.dueDate ? new Date(initialData?.dueDate).toISOString().split('T')[0] : "",
        leadId: initialData?.leadId || "",
        userId: initialData?.userId || "",
    });



    if (!isOpen) return null;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSubmit({
            ...formData,
            dueDate: formData.dueDate || null,
            leadId: formData.leadId || null,
            userId: formData.userId || null,
        });
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-500">
            <div className="w-full max-w-xl rounded-[40px] bg-white p-10 shadow-2xl shadow-blue-900/10 border border-zinc-100 animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                <div className="flex items-center justify-between mb-8">
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <Sparkles size={24} className="text-blue-500 animate-pulse" />
                            <h2 className="text-xl font-black tracking-tighter text-zinc-900">
                                {title}
                            </h2>
                        </div>
                        <p className="text-[10px] text-zinc-500 font-bold tracking-widest opacity-60">Task Management</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="rounded-2xl p-4 text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all border border-transparent hover:border-zinc-100"
                    >
                        <X size={24} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                <Target size={14} /> Task Title
                            </label>
                             <input
                                required
                                type="text"
                                placeholder="e.g. Conduct Tactical Review"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5 placeholder:text-zinc-300"
                            />
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-black tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                <AlignLeft size={14} /> Description
                            </label>
                            <textarea
                                rows={3}
                                placeholder="Elaborate on operational specifics..."
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 placeholder:text-zinc-300 resize-none"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-xs font-black tracking-widest text-zinc-500 ml-1">Status</label>
                                <select
                                    value={formData.status}
                                    onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="pending">Pending</option>
                                    <option value="in-progress">In Progress</option>
                                    <option value="completed">Completed</option>
                                </select>
                            </div>

                            <div className="space-y-2">\
                                <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <Calendar size={14} /> Due Date
                                </label>
                                <input
                                    type="date"
                                    value={formData.dueDate}
                                    onChange={(e) => setFormData({ ...formData, dueDate: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-blue-600 focus:outline-none focus:ring-4 focus:ring-blue-600/5"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <Target size={14} /> Related Lead
                                </label>
                                <select
                                    value={formData.leadId}
                                    onChange={(e) => setFormData({ ...formData, leadId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="">None</option>
                                    {leads.map((lead) => (
                                        <option key={lead.id} value={lead.id}>
                                            {lead.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-black  tracking-widest text-zinc-500 ml-1 flex items-center gap-2">
                                    <UserIcon size={14} /> Assignee
                                </label>
                                <select
                                    value={formData.userId}
                                    onChange={(e) => setFormData({ ...formData, userId: e.target.value })}
                                    className="w-full rounded-[20px] border border-zinc-100 bg-zinc-50/50 px-6 py-4 text-sm font-bold shadow-inner transition-all focus:bg-white focus:border-zinc-900 focus:outline-none focus:ring-4 focus:ring-zinc-900/5 appearance-none"
                                >
                                    <option value="">Unassigned</option>
                                    {users.map((user) => (
                                        <option key={user.id} value={user.id}>
                                            {user.name}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 pt-10">
                        <button
                            type="button"
                            onClick={onClose}
                            className="h-16 flex-1 rounded-[24px] text-xs font-black  tracking-widest text-zinc-400 hover:bg-zinc-50 hover:text-zinc-900 transition-all"
                        >
                            Discard
                        </button>
                        <button
                            type="submit"
                            disabled={isLoading}
                            className="h-16 flex-[2] flex items-center justify-center gap-4 rounded-[24px] bg-blue-600 text-xs font-black tracking-widest text-white shadow-2xl shadow-blue-600/30 hover:-translate-y-1 transition-all disabled:opacity-50 hover:bg-blue-700 active:scale-95"
                        >
                            {isLoading ? (
                                <Loader2 className="animate-spin" size={20} />
                            ) : (
                                <>
                                    <Save size={18} />
                                    Save
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { 
    Pencil, 
    Trash2, 
    CheckCircle2, 
    Clock, 
    AlertCircle,
    User,
    Target
} from "lucide-react";
import { Task } from "@/lib/services/task-service";

interface TaskTableProps {
    tasks: Task[];
    onEdit: (task: Task) => void;
    onDelete: (id: string) => void;
}

export function TaskTable({ tasks, onEdit, onDelete }: TaskTableProps) {

    const getStatusIcon = (status: string) => {
        switch (status) {
            case "completed":
                return <CheckCircle2 className="text-emerald-500" size={18} />;
            case "in-progress":
                return <Clock className="text-amber-500" size={18} />;
            default:
                return <AlertCircle className="text-zinc-400" size={18} />;
        }
    };

    const formatDate = (dateString?: string | null) => {
        if (!dateString) return "No date";
        return new Date(dateString).toLocaleDateString('en-US', {
            month: 'short',
            day: 'numeric',
            year: 'numeric'
        });
    };

    return (
        <div className="w-full overflow-hidden rounded-[40px] border border-zinc-200 bg-white shadow-2xl shadow-zinc-200/40 animate-in fade-in duration-500">
            <div className="overflow-x-auto">
                <table className="w-full text-left border-separate border-spacing-0">
                    <thead className="bg-zinc-50/50 text-zinc-400">
                        <tr>
                            <th className="px-8 py-7 font-black  tracking-[0.2em] text-[10px]">Task</th>
                            <th className="px-8 py-7 font-black  tracking-[0.2em] text-[10px]">Lead</th>
                            <th className="px-8 py-7 font-black  tracking-[0.2em] text-[10px]">Deadline</th>
                            <th className="px-8 py-7 font-black  tracking-[0.2em] text-[10px]">Status</th>
                            <th className="px-8 py-7 font-black  tracking-[0.2em] text-[10px]">Assignee</th>
                            <th className="px-8 py-7 text-right"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-zinc-100">
                    {tasks.map((task) => (
                        <tr key={task.id} className="group hover:bg-zinc-50/80 transition-all">
                            <td className="px-8 py-8">
                                <div className="space-y-2">
                                    <div className="font-black text-zinc-900 text-lg tracking-tighter">
                                        {task.title}
                                    </div>
                                    {task.description && (
                                        <div className="text-sm text-zinc-500 font-medium line-clamp-1 max-w-xs">
                                            {task.description}
                                        </div>
                                    )}
                                </div>
                            </td>
