"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import { User } from "../services/user-service";

interface AuthContextType {
    user: User | null;
    login: (user: User) => void;
    logout: () => void;
    isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
    const [user, setUser] = useState<User | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        // Load user from localStorage on mount
        const savedUser = localStorage.getItem("crm-user");
        if (savedUser) {
            try {
                const parsedUser = JSON.parse(savedUser);
                setUser(parsedUser);
            } catch (err) {
                console.error("Failed to parse saved user", err);
                localStorage.removeItem("crm-user");
            }
        }
        setIsLoading(false);
    }, []);

    const login = (userData: User) => {
        setUser(userData);
        localStorage.setItem("crm-user", JSON.stringify(userData));
    };

    const logout = () => {
        setUser(null);
        localStorage.removeItem("crm-user");
    };

    return (
        <AuthContext.Provider value={{ user, login, logout, isLoading }}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (context === undefined) {
        throw new Error("useAuth must be used within an AuthProvider");
    }
    return context;
}

import { supabase } from "../supabase";

export interface Task {
    id?: string;
    title: string;
    description?: string | null;
    status: string;
    dueDate?: string | null;
    leadId?: string | null;
    userId?: string | null;
    created_at?: string;
    updated_at?: string;
    lead?: {
        id: string;
        name: string;
    };
    user?: {
        id: string;
        name: string;
    };
}

export const taskService = {
    async getTasks() {
        const { data, error } = await supabase
            .from("tasks")
            .select("*, lead:leads(id, name), user:users(id, name)")
            .order("created_at", { ascending: false });

        if (error) throw error;
        return data as Task[];
    },

    async getTaskById(id: string) {
        const { data, error } = await supabase
            .from("tasks")
            .select("*, lead:leads(id, name), user:users(id, name)")
            .eq("id", id)
            .single();

        if (error) throw error;
        return data as Task;
    },

    async createTask(task: Omit<Task, "id" | "created_at" | "updated_at" | "lead" | "user">) {
        const { data, error } = await supabase
            .from("tasks")
            .insert([{
                title: task.title,
                description: task.description,
                status: task.status || "pending",
                dueDate: task.dueDate || null,
                leadId: task.leadId || null,
                userId: task.userId || null,
                updated_at: new Date().toISOString()
            }])
            .select()
            .single();

        if (error) throw error;
        return data as Task;
    },

    async updateTask(id: string, task: Partial<Task>) {
        // Remove nested objects and timestamps before updating
        const { lead: _lead, user: _user, created_at: _created_at, updated_at: _updated_at, ...updateData } = task;
        
        const { data, error } = await supabase
            .from("tasks")
            .update({
                ...updateData,
                updated_at: new Date().toISOString()
            })
            .eq("id", id)
            .select()
            .single();

        if (error) throw error;
        return data as Task;
    },

    async deleteTask(id: string) {
        const { error } = await supabase
            .from("tasks")
            .delete()
            .eq("id", id);

        if (error) throw error;
        return true;
    },
};
